    82→    hudTile3: c + rp.tile + 'UITile03.png',
    83→    hudTile4: c + rp.tile + 'UITile04.png',
    84→    upperBtn: `war3/Widgets/Console/${race}/${rp.lower}-console-buttonstates2.png`,
    85→    gold: 'war3/Feedback/Resources/ResourceGold.png',
    86→    lumber: 'war3/Feedback/Resources/ResourceLumber.png',
    87→    supply: `war3/Feedback/Resources/Resource${race}.png`,
    88→    escBtnBg: (race === 'Human')
    89→      ? eH + 'human-options-menu-background.png'
    90→      : e + rp.esc + '-options-button-background.png',
    91→    escBtnBorder: eH + 'human-options-button-border-up.png',
    92→    escBtnHighlight: e + rp.esc + '-options-button-highlight.png',
    93→    escMenuBg: e + rp.esc + '-options-menu-background.png',
    94→    escMenuBorder: e + rp.esc + '-options-menu-border.png',
    95→    cbBg: eH + 'checkbox-background.png',
    96→    cbCheck: (race === 'Human') ? eH + 'checkbox-check.png'
    97→           : (race === 'Undead') ? 'war3/Widgets/EscMenu/Undead/undead-checkbox-check.png'
    98→           : 'war3/Widgets/Glues/GlueScreen-Checkbox-Check.png',
    99→    cbDepressed: (race === 'Human') ? eH + 'checkbox-depressed.png'
   100→               : e + rp.esc + '-checkbox-depressed.png',
   101→    rbBg: eH + 'radiobutton-background.png',
   102→    rbDot: eH + 'radiobutton-button.png',
   103→    sliderBg: eH + 'slider-background.png',
