   112→    xpBorder: `war3/Feedback/XpBar/${rp.lower}-xpbar-border.png`,
   113→    buildFill: `war3/Feedback/BuildProgressBar/${rp.lower}-buildprogressbar-fill.png`,
   114→    buildBorder: `war3/Feedback/BuildProgressBar/${rp.lower}-buildprogressbar-border.png`,
   115→    loadBg: 'war3/Glues/Loading/LoadBar/Loading-BarBackground.png',
   116→    loadFill: 'war3/Glues/Loading/LoadBar/Loading-BarFill.png',
   117→    loadBorder: 'war3/Glues/Loading/LoadBar/Loading-BarBorder.png',
   118→    loadGlass: 'war3/Glues/Loading/LoadBar/Loading-BarGlass.png',
   119→    glueBg: 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBackground.png',
   120→    glueBorder: 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBorder.png',
   121→    glueBgDown: 'war3/Widgets/Glues/GlueScreen-Button1-BackdropBackground-Down.png',
