     1→import { useEffect, useRef } from 'react';
     2→import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
     3→import { mat3, mat4, quat, vec3 } from 'gl-matrix';
     4→import type { Race } from '../lib/types';
     5→
     6→type ModelType = ReturnType<typeof parseMDX>;
     7→type WorkerSide = 'left' | 'right';
     8→
     9→interface WorkerUnitConfig {
    10→  modelPath: string;
    11→  textures: Record<string, string>;
    12→}
    13→
    14→const WORKER_UNIT_CONFIG: Record<Race, WorkerUnitConfig> = {
    15→  Human: { modelPath: './models/worker-units/Human/peasant.mdx', textures: { 'textures/peasant.blp': './models/worker-units/textures/Peasant.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
    16→  Orc: { modelPath: './models/worker-units/Orc/peon.mdx', textures: { 'units/orc/peon/peon.blp': './models/worker-units/Orc/peon.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
    17→  NightElf: { modelPath: './models/worker-units/NightElf/Archer.mdx', textures: { 'textures/ranger.blp': './models/worker-units/textures/Ranger.blp', 'textures/star2_32.blp': './models/worker-units/textures/star2_32.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
    18→  Undead: { modelPath: './models/worker-units/Undead/Acolyte.mdx', textures: { 'textures/acolyte.blp': './models/worker-units/textures/Acolyte.blp', 'textures/green_star.blp': './models/worker-units/textures/Green_Star.blp', 'textures/demonrune3.blp': './models/worker-units/textures/DemonRune3.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
    19→};
    20→
    21→const modelCache = new Map<string, ModelType>();
    22→const blpCache = new Map<string, ImageData[]>();
    23→
    24→function normalizeTexturePath(textureImage: string): string { return textureImage.replaceAll('\\', '/').toLowerCase(); }
    25→
    26→function getTexturePath(textureImage: string, race: Race): string | null {
    27→  const normalized = normalizeTexturePath(textureImage);
    28→  if (!normalized) return null;
    29→  return WORKER_UNIT_CONFIG[race].textures[normalized] || null;
    30→}
    31→
    32→async function loadModel(path: string): Promise<ModelType> {
    33→  const cached = modelCache.get(path);
    34→  if (cached) return cached;
    35→  const res = await fetch(path);
    36→  if (!res.ok) throw new Error(`Failed to load worker unit model: ${path}`);
    37→  const ab = await res.arrayBuffer();
    38→  const model = parseMDX(ab);
    39→  modelCache.set(path, model);
    40→  return model;
    41→}
    42→
    43→async function loadBLPMips(path: string): Promise<ImageData[]> {
    44→  const cached = blpCache.get(path);
    45→  if (cached) return cached;
    46→  const res = await fetch(path);
    47→  if (!res.ok) throw new Error(`Failed to load worker unit texture: ${path}`);
    48→  const ab = await res.arrayBuffer();
    49→  const blp = decodeBLP(ab);
    50→  const mips: ImageData[] = [];
    51→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
    52→  for (let i = 0; i < maxLevels; i++) {
    53→    const w = blp.width >> i; const h = blp.height >> i;
    54→    if (w <= 0 || h <= 0) break;
    55→    try {
    56→      const img = getBLPImageData(blp, i);
    57→      if (!img || !img.width || !img.height) break;
    58→      mips.push(new ImageData(new Uint8ClampedArray(img.data), img.width, img.height));
    59→      if (img.width === 1 && img.height === 1) break;
    60→    } catch { break; }
    61→  }
    62→  if (mips.length === 0) throw new Error(`No mip levels decoded for worker unit texture: ${path}`);
    63→  blpCache.set(path, mips);
    64→  return mips;
    65→}
    66→
    67→function findIdleSequenceIndex(model: ModelType, race: Race): number {
    68→  const sequences = model.Sequences || [];
    69→  if (sequences.length === 0) return 0;
    70→  const sequenceNames = sequences.map((seq) => (seq.Name || '').toLowerCase());
    71→  const preferencesByRace: Record<Race, readonly string[]> = {
    72→    Human: ['stand work', 'stand lumber', 'stand ready', 'stand gold', 'stand - 3', 'stand -3', 'stand 2', 'stand - 2', 'stand'],
    73→    Orc: ['stand work', 'stand - stretch', 'stand - itch head', 'stand - talk gesture', 'stand 2', 'stand - 2', 'stand'],
    74→    NightElf: ['stand ready', 'stand - 3', 'stand -3', 'stand 2', 'stand - 2', 'stand'],
    75→    Undead: ['stand work', 'stand 2', 'stand - 2', 'stand ready', 'stand'],
    76→  };
    77→  for (const pref of preferencesByRace[race]) {
    78→    const idx = sequenceNames.findIndex((name) => name.includes(pref));
    79→    if (idx >= 0) return idx;
    80→  }
    81→  const fallback = sequenceNames.findIndex((name) => name.includes('stand') && !name.includes('death') && !name.includes('decay'));
    82→  return fallback >= 0 ? fallback : 0;
    83→}
    84→
    85→function getSequenceInterval(model: ModelType, index: number): { start: number; length: number } {
    86→  const seq = model.Sequences?.[index];
    87→  const start = seq?.Interval?.[0] ?? 0;
    88→  const end = seq?.Interval?.[1] ?? (start + 1000);
    89→  return { start, length: Math.max(1, end - start) };
    90→}
    91→
    92→function getExtentsForSequence(model: ModelType, sequenceIndex: number): { min: readonly [number, number, number] | null; max: readonly [number, number, number] | null } {
    93→  const seq = model.Sequences?.[sequenceIndex];
    94→  const seqMin = seq?.MinimumExtent; const seqMax = seq?.MaximumExtent;
    95→  if (seqMin && seqMax) return { min: [seqMin[0], seqMin[1], seqMin[2]], max: [seqMax[0], seqMax[1], seqMax[2]] };
    96→  const modelMin = model.Info?.MinimumExtent; const modelMax = model.Info?.MaximumExtent;
    97→  if (modelMin && modelMax) return { min: [modelMin[0], modelMin[1], modelMin[2]], max: [modelMax[0], modelMax[1], modelMax[2]] };
    98→  return { min: null, max: null };
    99→}
   100→
   101→interface WorkerUnitModelProps { race: Race; side: WorkerSide; }
   102→
   103→export default function WorkerUnitModel(props: WorkerUnitModelProps) {
   104→  const canvasRef = useRef<HTMLCanvasElement>(null);
   105→  const stateRef = useRef({
   106→    gl: null as WebGLRenderingContext | WebGL2RenderingContext | null,
   107→    modelRenderer: null as ModelRenderer | null,
   108→    resizeObserver: null as ResizeObserver | null,
   109→    rafId: 0, disposed: false, initVersion: 0,
   110→    sequenceIndex: 0, sequenceStart: 0, sequenceLength: 1000, animStartMs: 0,
   111→    mvMatrix: mat4.create(), pMatrix: mat4.create(), worldCameraMatrix: mat4.create(),
   112→    cameraPos: vec3.create(), cameraTarget: vec3.create(), cameraQuat: quat.create(),
   113→    cameraFov: 0.78, cameraNear: 8, cameraFar: 2400,
   114→  });
   115→
   116→  useEffect(() => {
   117→    const s = stateRef.current;
   118→    const canvas = canvasRef.current!;
   119→
   120→    const destroyRenderer = () => {
   121→      if (!s.modelRenderer) return;
   122→      try { s.modelRenderer.destroy(); } catch (err) { console.warn('worker unit renderer destroy failed', err); }
   123→      finally { s.modelRenderer = null; }
   124→    };
   125→
   126→    const updateProjection = () => {
   127→      const aspect = Math.max(1e-6, canvas.clientWidth / Math.max(1, canvas.clientHeight));
   128→      mat4.perspective(s.pMatrix, s.cameraFov, aspect, s.cameraNear, s.cameraFar);
   129→    };
   130→
   131→    const resizeCanvas = () => {
   132→      if (!s.gl) return;
   133→      const dpr = window.devicePixelRatio || 1;
   134→      const w = Math.max(1, Math.round(canvas.clientWidth * dpr));
   135→      const h = Math.max(1, Math.round(canvas.clientHeight * dpr));
   136→      if (canvas.width !== w || canvas.height !== h) { canvas.width = w; canvas.height = h; }
   137→      s.gl.viewport(0, 0, w, h);
   138→      updateProjection();
   139→    };
   140→
   141→    const configureCamera = (model: ModelType, sequenceIdx: number) => {
   142→      const extents = getExtentsForSequence(model, sequenceIdx);
   143→      const extMin = extents.min; const extMax = extents.max;
   144→      if (extMin && extMax) {
   145→        const cx = (extMin[0] + extMax[0]) * 0.5, cy = (extMin[1] + extMax[1]) * 0.5, cz = (extMin[2] + extMax[2]) * 0.5;
   146→        const dx = extMax[0] - extMin[0], dy = extMax[1] - extMin[1], dz = extMax[2] - extMin[2];
   147→        const rawRadius = Math.hypot(dx, dy, dz) * 0.5;
   148→        const radius = Math.min(190, Math.max(100, rawRadius));
   149→        const height = Math.min(220, Math.max(90, dz));
   150→        vec3.set(s.cameraPos, cx + radius * 0.42, cy - radius * 2.25, cz + height * 0.62);
   151→        vec3.set(s.cameraTarget, cx, cy, cz + height * 0.18);
   152→        s.cameraFov = 0.86; s.cameraNear = Math.max(8, radius * 0.08); s.cameraFar = Math.max(s.cameraNear + 300, radius * 11.5);
   153→      } else {
   154→        vec3.set(s.cameraPos, 48, -420, 180); vec3.set(s.cameraTarget, 0, 0, 100);
   155→        s.cameraFov = 0.78; s.cameraNear = 8; s.cameraFar = 2200;
   156→      }
   157→      mat4.lookAt(s.mvMatrix, s.cameraPos, s.cameraTarget, vec3.fromValues(0, 0, 1));
   158→      if (mat4.invert(s.worldCameraMatrix, s.mvMatrix)) {
   159→        const rot = mat3.create(); mat3.fromMat4(rot, s.worldCameraMatrix);
   160→        quat.fromMat3(s.cameraQuat, rot); quat.normalize(s.cameraQuat, s.cameraQuat);
   161→      } else { quat.identity(s.cameraQuat); }
   162→    };
   163→
   164→    const startRenderLoop = () => {
   165→      const speed = 0.8;
   166→      const tick = (now: number) => {
   167→        if (s.disposed) return;
   168→        s.rafId = requestAnimationFrame(tick);
   169→        if (!s.gl || !s.modelRenderer) return;
   170→        resizeCanvas();
   171→        const elapsed = (now - s.animStartMs) * speed;
   172→        const frame = s.sequenceStart + (elapsed % s.sequenceLength);
   173→        s.modelRenderer.setSequence(s.sequenceIndex);
   174→        s.modelRenderer.setFrame(frame);
   175→        s.modelRenderer.update(0);
   176→        s.gl.clearColor(0, 0, 0, 0);
   177→        s.gl.clear(s.gl.COLOR_BUFFER_BIT | s.gl.DEPTH_BUFFER_BIT);
   178→        s.modelRenderer.render(s.mvMatrix, s.pMatrix, { env: false, wireframe: false });
   179→      };
   180→      s.rafId = requestAnimationFrame(tick);
   181→    };
   182→
   183→    const initForRace = async (race: Race, _side: WorkerSide) => {
   184→      const version = ++s.initVersion;
   185→      const cfg = WORKER_UNIT_CONFIG[race];
   186→      const model = await loadModel(cfg.modelPath);
   187→      if (s.disposed || version !== s.initVersion || !s.gl) return;
   188→      destroyRenderer();
   189→      s.modelRenderer = new ModelRenderer(model);
   190→      s.modelRenderer.initGL(s.gl);
