function getCheckboxDepressedPath(race: Race): string {
  if (race === "Orc") return "./buttons/checkbox/orc-checkbox-depressed.blp";
  if (race === "NightElf")
    return "./buttons/checkbox/nightelf-checkbox-depressed.blp";
  if (race === "Undead")
    return "./buttons/checkbox/undead-checkbox-depressed.blp";
  return "./buttons/checkbox/checkbox-depressed.blp";
}

function getEscSliderKnobPath(race: Race): string {
  if (race === "Orc") return "./buttons/slider/orc-slider-knob.blp";
  if (race === "NightElf") return "./buttons/slider/nightelf-slider-knob.blp";
  if (race === "Undead") return "./buttons/slider/undead-slider-knob.blp";
  return "./buttons/slider/slider-knob.blp";
}

function getEscMenuBackgroundPath(race: Race): string {
  if (race === "Orc") return "./buttons/esc/orc/orc-options-menu-background.blp";
  if (race === "NightElf")
    return "./buttons/esc/nightelf/nightelf-options-menu-background.blp";
  if (race === "Undead")
    return "./buttons/esc/undead/undead-options-menu-background.blp";
  return "./buttons/esc/human/human-options-menu-background.blp";
}

function getCardSectionBorderPath(race: Race): string {
  if (race === "Orc") return "/buttons/esc/orc/orc-options-menu-border.blp";
