    window.addEventListener("resize", syncViewportWidth);

    const goldTimer = window.setInterval(() => {
      setGoldValue((prev: number) =>
        Math.min(maxResourceValue, prev + resourceStep),
      );
    }, goldTickMs);
    const lumberTimer = window.setInterval(() => {
      setLumberValue((prev: number) =>
        Math.min(maxResourceValue, prev + resourceStep),
      );
    }, lumberTickMs);
    const supplyTimer = window.setInterval(() => {
      setSupplyUsed((prev: number) => Math.min(prev + 1, supplyCap));
    }, supplyTickMs);
    const supplyCapTimer = window.setInterval(() => {
      setSupplyCap((prev: number) => Math.min(maxSupplyCap, prev + 10));
    }, supplyCapTickMs);
    const barsTimer = window.setInterval(() => {
      setBarCycle((prev: number) => prev + 1);
    }, 1400);
    const progressAnimTimer = window.setInterval(() => {
      setProgressAnimMs(
        (prev: number) => (prev + progressAnimTickMs) % progressAnimCycleMs,
      );
    }, progressAnimTickMs);

    const factionRaces: { name: string; race: Race }[] = [
      { name: "Human", race: "Human" },
      { name: "Orc", race: "Orc" },
      { name: "Night Elf", race: "NightElf" },
      { name: "Undead", race: "Undead" },
    ];
    void Promise.all(
      factionRaces.map((f) => loadBlpDataUrl(getCardSectionBorderPath(f.race))),
    ).then((urls) => {
      const record: Record<string, string> = {};
      factionRaces.forEach((f, i) => {
        record[f.name] = urls[i];
      });
      setFactionBorderUrls(record);
    });

    return () => {
      window.removeEventListener("resize", syncViewportWidth);
      clearInterval(goldTimer);
      clearInterval(lumberTimer);
      clearInterval(supplyTimer);
      clearInterval(supplyCapTimer);
      clearInterval(barsTimer);
      clearInterval(progressAnimTimer);
